const crypto = require('crypto');

function verifyWebhookSignature(req, secret) {
  const payload = req.rawBody;
  const provided = req.headers['x-signature-sha256'];

  if (!provided) {
    return { valid: false, status: 401, reason: 'missing signature' };
  }

  const expected = crypto
    .createHmac('sha256', secret)
    .update(payload)
    .digest('hex');

  if (provided !== expected) {
    return { valid: false, status: 401, reason: 'signature mismatch' };
  }

  return { valid: true, status: 200 };
}

function bytesToId(bytes) {
  if (!Array.isArray(bytes) || bytes.length === 0 || bytes.length > 6) {
    throw new RangeError('bytes must be an array of 1–6 values');
  }

  let result = 0;
  for (let i = 0; i < bytes.length; i++) {
    result = (result << 8) | (bytes[i] & 0xff);
  }

  return result;
}

