function debounce(fn, delayMs) {
  let timerId = null;
  return function debounced(...args) {
    if (timerId !== null) {
      clearTimeout(timerId);
    }
    timerId = setTimeout(() => {
      timerId = null;
      fn.apply(this, args);
    }, delayMs);
  };
}

function binarySearch(arr, target) {
  let lo = 0;
  let hi = arr.length - 1;
  while (lo <= hi) {
    const mid = lo + Math.floor((hi - lo) / 2);
    if (arr[mid] === target) return mid;
    if (arr[mid] < target) lo = mid + 1;
    else hi = mid - 1;
  }
  return -1;
}

class LRUCache {
  constructor(capacity) {
    this.capacity = capacity;
    this.map = new Map();
  }

  get(key) {
    if (!this.map.has(key)) return -1;
    const value = this.map.get(key);
    this.map.delete(key);
    this.map.set(key, value);
    return value;
  }

  put(key, value) {
    if (this.map.has(key)) {
      this.map.delete(key);
    } else if (this.map.size >= this.capacity) {
      const lruKey = this.map.keys().next().value;
      this.map.delete(lruKey);
    }
    this.map.set(key, value);
  }
}

function flattenDeep(arr) {
  const result = [];
  function walk(items) {
    for (const item of items) {
      if (Array.isArray(item)) {
        walk(item);
      } else {
        result.push(item);
      }
    }
  }
  walk(arr);
  return result;
}

class TokenBucket {
  constructor(capacity, refillRatePerMs) {
    this.capacity = capacity;
    this.tokens = capacity;
    this.refillRatePerMs = refillRatePerMs;
    this.lastRefillTime = Date.now();
  }

  _refill() {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    this.tokens = Math.min(
      this.capacity,
      this.tokens + elapsed * this.refillRatePerMs
    );
    this.lastRefillTime = now;
  }

  consume(n) {
    this._refill();
    if (this.tokens < n) return false;
    this.tokens -= n;
    return true;
  }
}

function memoize(fn) {
  const cache = new Map();
  return function memoized(key) {
    if (cache.has(key)) {
      return cache.get(key);
    }
    const result = fn.call(this, key);
    cache.set(key, result);
    return result;
  };
}

class EventEmitter {
  constructor() {
    this._listeners = new Map();
  }

  on(event, listener) {
    if (!this._listeners.has(event)) this._listeners.set(event, []);
    this._listeners.get(event).push({ fn: listener, once: false });
    return this;
  }

  once(event, listener) {
    if (!this._listeners.has(event)) this._listeners.set(event, []);
    this._listeners.get(event).push({ fn: listener, once: true });
    return this;
  }

  off(event, listener) {
    if (!this._listeners.has(event)) return this;
    this._listeners.set(
      event,
      this._listeners.get(event).filter(entry => entry.fn !== listener)
    );
    return this;
  }

  emit(event, ...args) {
    if (!this._listeners.has(event)) return false;
    const remaining = [];
    for (const entry of this._listeners.get(event)) {
      entry.fn(...args);
      if (!entry.once) remaining.push(entry);
    }
    this._listeners.set(event, remaining);
    return true;
  }
}
